import{_ as o,o as e,c as t,a4 as l}from"./chunks/framework.Bz0lZ1uX.js";const h=JSON.parse('{"title":"名言警句","description":"","frontmatter":{},"headers":[],"relativePath":"materials/名言警句/index.md","filePath":"materials/名言警句/index.md","lastUpdated":null}'),a={name:"materials/名言警句/index.md"},c=l('<h1 id="名言警句" tabindex="-1">名言警句 <a class="header-anchor" href="#名言警句" aria-label="Permalink to &quot;名言警句&quot;">​</a></h1><p>名言警句凝练深刻，言简意赅，是议论文写作中极具说服力的理论论据。</p><h2 id="关于奋斗与坚持" tabindex="-1">关于奋斗与坚持 <a class="header-anchor" href="#关于奋斗与坚持" aria-label="Permalink to &quot;关于奋斗与坚持&quot;">​</a></h2><blockquote><p>锲而舍之，朽木不折；锲而不舍，金石可镂。 ——荀子《劝学》</p></blockquote><blockquote><p>古之成大事者，不惟有超世之才，亦必有坚忍不拔之志。 ——苏轼</p></blockquote><blockquote><p>世上只有一种英雄主义，就是在认清生活真相之后依然热爱生活。 ——罗曼·罗兰</p></blockquote><blockquote><p>不积跬步，无以至千里；不积小流，无以成江海。 ——荀子《劝学》</p></blockquote><blockquote><p>千磨万击还坚劲，任尔东西南北风。 ——郑燮《竹石》</p></blockquote><h2 id="关于创新与突破" tabindex="-1">关于创新与突破 <a class="header-anchor" href="#关于创新与突破" aria-label="Permalink to &quot;关于创新与突破&quot;">​</a></h2><blockquote><p>苟日新，日日新，又日新。 ——《礼记·大学》</p></blockquote><blockquote><p>穷则变，变则通，通则久。 ——《周易》</p></blockquote><blockquote><p>踩着别人的脚步走路的人，永远不会留下自己的脚印。 ——爱因斯坦</p></blockquote><blockquote><p>创新是一个民族进步的灵魂，是国家兴旺发达的不竭动力。 ——江泽民</p></blockquote><blockquote><p>学我者生，似我者死。 ——齐白石</p></blockquote><h2 id="关于理想与信念" tabindex="-1">关于理想与信念 <a class="header-anchor" href="#关于理想与信念" aria-label="Permalink to &quot;关于理想与信念&quot;">​</a></h2><blockquote><p>志不立，天下无可成之事。 ——王阳明</p></blockquote><blockquote><p>三军可夺帅也，匹夫不可夺志也。 ——孔子</p></blockquote><blockquote><p>理想信念就是共产党人精神上的&quot;钙&quot;，没有理想信念，理想信念不坚定，精神上就会&quot;缺钙&quot;，就会得&quot;软骨病&quot;。 ——习近平</p></blockquote><blockquote><p>生活好比旅行，理想是旅行的路线。失去了路线，只好停止前进了。 ——雨果</p></blockquote><blockquote><p>志之所趋，无远弗届；穷山距海，不能限也。 ——《格言联璧》</p></blockquote><h2 id="关于责任与担当" tabindex="-1">关于责任与担当 <a class="header-anchor" href="#关于责任与担当" aria-label="Permalink to &quot;关于责任与担当&quot;">​</a></h2><blockquote><p>天下兴亡，匹夫有责。 ——顾炎武</p></blockquote><blockquote><p>先天下之忧而忧，后天下之乐而乐。 ——范仲淹</p></blockquote><blockquote><p>苟利国家生死以，岂因祸福避趋之。 ——林则徐</p></blockquote><blockquote><p>为天地立心，为生民立命，为往圣继绝学，为万世开太平。 ——张载</p></blockquote><blockquote><p>无穷的远方，无数的人们，都和我有关。 ——鲁迅</p></blockquote><h2 id="关于学习与求知" tabindex="-1">关于学习与求知 <a class="header-anchor" href="#关于学习与求知" aria-label="Permalink to &quot;关于学习与求知&quot;">​</a></h2><blockquote><p>学而不思则罔，思而不学则殆。 ——孔子</p></blockquote><blockquote><p>吾生也有涯，而知也无涯。 ——庄子</p></blockquote><blockquote><p>读书破万卷，下笔如有神。 ——杜甫</p></blockquote><blockquote><p>问渠那得清如许？为有源头活水来。 ——朱熹</p></blockquote><blockquote><p>博学之，审问之，慎思之，明辨之，笃行之。 ——《礼记·中庸》</p></blockquote><h2 id="关于团结与合作" tabindex="-1">关于团结与合作 <a class="header-anchor" href="#关于团结与合作" aria-label="Permalink to &quot;关于团结与合作&quot;">​</a></h2><blockquote><p>二人同心，其利断金。 ——《周易》</p></blockquote><blockquote><p>能用众力，则无敌于天下矣；能用众智，则无畏于圣人矣。 ——孙权</p></blockquote><blockquote><p>一滴水只有放进大海里才永远不会干涸。 ——雷锋</p></blockquote><blockquote><p>单丝不成线，独木不成林。 ——民谚</p></blockquote><blockquote><p>人心齐，泰山移。 ——民谚</p></blockquote><h2 id="关于时间与珍惜" tabindex="-1">关于时间与珍惜 <a class="header-anchor" href="#关于时间与珍惜" aria-label="Permalink to &quot;关于时间与珍惜&quot;">​</a></h2><blockquote><p>盛年不重来，一日难再晨。及时当勉励，岁月不待人。 ——陶渊明</p></blockquote><blockquote><p>少壮不努力，老大徒伤悲。 ——《长歌行》</p></blockquote><blockquote><p>一寸光阴一寸金，寸金难买寸光阴。 ——民谚</p></blockquote><blockquote><p>逝者如斯夫，不舍昼夜。 ——孔子</p></blockquote><blockquote><p>明日复明日，明日何其多。我生待明日，万事成蹉跎。 ——文嘉</p></blockquote><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li><strong>准确引用</strong>: 确保名言的出处和内容准确无误</li><li><strong>恰当解读</strong>: 引用后要适当解释，与论点建立联系</li><li><strong>避免堆砌</strong>: 一篇文章引用2-3条名言即可，不宜过多</li><li><strong>古今结合</strong>: 适当搭配古代名言和现代名人名言</li><li><strong>灵活化用</strong>: 可以将名言融入自己的语言表达中，不必完全照搬原文</li></ol>',46),u=[c];function q(b,p,k,r,i,n){return e(),t("div",null,u)}const d=o(a,[["render",q]]);export{h as __pageData,d as default};
